def count_adjacent_same_color(n, queries):
    nums = [0] * n
    answer = []
    current_count = 0

    for index, color in queries:
        old_color = nums[index]

        if old_color == color:
            answer.append(current_count)
            continue

        # Check left neighbor before change
        if index > 0 and nums[index - 1] != 0:
            if nums[index - 1] == old_color:
                current_count -= 1
            if nums[index - 1] == color:
                current_count += 1

        # Check right neighbor before change
        if index < n - 1 and nums[index + 1] != 0:
            if nums[index + 1] == old_color:
                current_count -= 1
            if nums[index + 1] == color:
                current_count += 1

        nums[index] = color
